var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"얘들아, 그쪽은 끝났어?","JPN":"みんな、そっちは終わったの？","ENG":"Guys, are you done on that side?","TWN":"你們那邊結束了嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"이쪽은 이상 없어요, 호진 언니.","JPN":"ここは異常ありません、マユミさん。","ENG":"All's clear on this side, Hojin.","TWN":"鎬真姐，這邊都正常喔。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"여기는 에이전트 소림. 이쪽은 이상 없다. 적은 모두 소탕했다.","JPN":"こちらエージェント・ミズキ。当方も異常なし。敵の掃討、完了。","ENG":"This is Agent Sorim. All's clear on this side, too. All enemies eliminated.","TWN":"這裡是代理人蕭林，這邊都正常，敵人已全數殲滅。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그럼 이걸로 끝인가보네. 오늘도 다들 수고했어!","JPN":"それじゃあ、終わりだね。今日もみんなお疲れ様！","ENG":"Then, we can call it a day. Good job, everyone!","TWN":"那應該差不多都結束了，大家今天也都辛苦囉～"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"다들 고생했어요, 여러분~","JPN":"お疲れ様でした！","ENG":"Good work, people!","TWN":"大家辛苦了～"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DUCK_SUMMON_NULL_NULL","text":{"KOREA":"팩- 패액-","JPN":"ガガー、グアッ！","ENG":"Qua-quack.","TWN":"嗶- 嗶嗶-"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BEAR_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DUCK_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L12_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"훗, 본관의 실력을 생각하면 간단한 임무였다.","JPN":"ふふっ、本官にとっては簡単な任務だった。","ENG":"Heh, that mission was a walk in the park for this soldier right here.","TWN":"哼～對本官來說這根本只是小菜一碟！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"자, 그럼 수고했다는 의미로 돌아가다 분식집이라도 갈까? 오늘은 내가 쏠게!","JPN":"さて、お疲れ様会で何か美味しいものでも食べにいく～？　私が奢るから！","ENG":"Okay, then how about we go grab a bite, to celebrate our hard work today? It's on me!","TWN":"好吧！大家今天這麼辛苦，一起去小吃店吧～今天我請客！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"와아, 호진 언니 최고에요!","JPN":"やった、マユミさんサイコー！","ENG":"Yay! Hojin, you're the best!","TWN":"哇～鎬真姐棒棒！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"오오, 힘든 전투 후에 부대원들끼리 나누는 한 잔은 각별하지!","JPN":"おお、ひと汗かいた後飲むアレは、至福の一杯である！","ENG":"Ooo, there's nothing like having a drink with your comrades after a hard day of battle.","TWN":"嗯嗯！辛苦戰鬥後，和夥伴們一起喝一杯特別有滋味！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그 맛을 알다니, 호진 대원은 역시 연장자답다.","JPN":"その味の良さをわかるとは、さすがマユミ隊員は年長者だ。","ENG":"I'm glad you know that, Operative Hojin.","TWN":"鎬真隊員竟然也知道這個道理，真不愧是有年紀的！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"콜라 얘기하는 거 맞지?","JPN":"えっと、コーラのことだよね……？","ENG":"You mean soda, right?","TWN":"你的喝一杯是指可樂吧？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"헤헤, 그럼 빨리 뒷정리하고 분식집으로……","JPN":"えへへっ、ではササッと片付けてご飯……","ENG":"Heh heh. Then, let's finish things up and go grab a bite!","TWN":"嘿嘿～那我們趕快收拾收拾出發吧……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 이 소리는?","JPN":"あれ、この音は？","ENG":"Ah, wait!","TWN":"嗯？這是什麼聲音？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"래빗센스에 신호가 왔어! 여기 어디 도와달라는 동물이 있는 것 같아!","JPN":"ラビットセンスにシグナルを感知！　この辺に助けを求めている動物がいるみたい！","ENG":"Rabbit Sense has got a signal. There's a distressed animal somewhere around here!","TWN":"我的兔兔雷達接收到訊號！這裡有需要幫助的小動物！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"여긴 침식위험구역인데? 위험할지도 모르니 빨리 찾아보자!","JPN":"ここは侵食危険区域だよね？\\n危ない状態かもしれないから、はやく見つけてあげよう！","ENG":"We're in a Corruption danger zone. It might be dangerous. We'd better hurry!","TWN":"這裡是侵蝕危險區域，我怕會有危險，大家趕快找找！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"간만의 구출작전이로군! 본관이 선두에 서겠다!","JPN":"久々の救出作戦だな！　本官が先頭に立つ！","ENG":"The first rescue operation after a long time. I'll take the lead!","TWN":"久違的救援大作戰嗎？就由本官來打頭陣吧！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 소림아! 신호는 반대쪽이야!","JPN":"まって、ミズキ！　シグナルは反対側だよ！","ENG":"Ah, Sorim! It's the opposite side!","TWN":"喂！蕭林～信號是從反方向發出來的啦～"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"냐앙!","JPN":"ニャーン！","ENG":"Meow!","TWN":"喵喵～"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_CAT_DAMAGE_DOWN"},{"id":"L29_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"오, 이런 인형 같은 울음소리라니.","JPN":"おお、実に可愛い鳴き声だな。","ENG":"Oh, he even sounds cute.","TWN":"喔，這是什麼可愛的奶貓音！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"와아, 정말 귀엽다! 꼭 귀엽기 위해 태어난 것 같아.","JPN":"わぁ～、かわいい！　かわいいって言われるために生まれてきたみたい。","ENG":"Whoa, he's so cute! It's as if he's born to be cute.","TWN":"哇～超可愛的！牠是吃可愛長大的嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"게다가 사람도 엄청 잘 따르고요.","JPN":"しかも人懐っこいですね。","ENG":"He's so friendly, too.","TWN":"而且還很親人呢！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"이거 보세요, 장난감을 흔들어주면…","JPN":"ほら、オモチャを振ると……","ENG":"Look, if I shake this toy...","TWN":"你們看～牠好像也喜歡玩玩具…"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"냥! 냥!","JPN":"ミャー！　ミャー！","ENG":"Meow! Meow!","TWN":"喵！喵！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"귀여워~!","JPN":"かわいい～っ！","ENG":"So cute!","TWN":"可愛～！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"빠르게 움직이는 타깃을 놓치지 않는 저 순발력. 분명 사냥꾼의 기질을 타고났군.","JPN":"素早く動くターゲットを見逃さないあの瞬発力。\\n狩人の気質を持っているな。","ENG":"Look how quickly he moves to catch the moving target. He's a born hunter.","TWN":"瞧我如此迅速精準地找到目標物，我果然是天生的獵人！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"장난끼가 많은 거 보니까, 아무래도 호기심에 여기까지 온 것 같아요.","JPN":"わんぱくな性格の子だから、好奇心でここまで来てしまったようです。","ENG":"He's so playful. He must have come this far just out of curiosity.","TWN":"你們看牠還很貪玩的樣子，應該是因為好奇心才會來到這裡吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그러게. 무슨 일이 일어나기 전에 찾아서 정말 다행이야.","JPN":"そうね。危ない目にあう前に見つかってよかった。","ENG":"I agree. I'm glad we've found him before something bad happened to him.","TWN":"就是說，幸好我們在牠出事前就先找到牠。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그런데, 이 애… 어떻게 한담?","JPN":"ところでこの子……どうする？","ENG":"By the way... what do we do with him?","TWN":"不過…接下來該怎麼辦？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"역시 우리가 데리고 있는 편이 안전하겠지?","JPN":"やっぱり私たちが保護したほうが安全かな？","ENG":"We should take him with us, right?","TWN":"牠跟著我們應該比較安全吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"막시무스를 혼자 내버려두는 건 위험하다.","JPN":"マクシムスを一人にさせるのは危険だ。","ENG":"Maximus shouldn't be left alone. It's too dangerous.","TWN":"我們把咖啡貓扔在這裡的話，牠會有危險吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"우리 화이트래빗이 정기적으로 후원하고 있는 동물보호센터에 연락하는 편을 권장한다.","JPN":"我々が定期的に後援している動物保護センターに連絡することを勧める。","ENG":"I suggest we contact the animal shelter that we White Rabbits support regularly.","TWN":"我看還是和有長期合作的動保會聯絡吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그게…… 요즘 새 주인을 찾지 못하는 동물들이 워낙 많아서 당분간 새로 들어올 자리를 만들기 어렵대.","JPN":"それがね……最近、里親さんが見つからない動物が多すぎて、\\nしばらく新しい子を受け入れるのは難しいって。","ENG":"Well... That place is filled to the brim with abandoned animals right now. It can't accept any more.","TWN":"可是……最近有很多找不到主人的浪浪，應該沒有位置可以容納牠。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"게다가 우리 아지트는 임시 보호 중인 여우가 있어서 고양이를 들여놓기 곤란해.","JPN":"それにうちのアジトには一時保護中のキツネがいるから、\\n猫ちゃんを連れて帰るのは難しいよね。","ENG":"We also have the fox at the clubhouse that we're temporarily housing at the moment. The cat can't be there, either.","TWN":"況且我們的基地目前還有中途狐狸，可能不適合養貓。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그렇다. 동물에게 맞지 않는 환경에서 억지로 키우려고 하면 스트레스만 줄 뿐!","JPN":"そうだな。不適切な環境に無理やり連れて行くのは\\n動物にとってストレスになるだけである！","ENG":"No, he can't. Animals get stressed out if they're kept where they shouldn't.","TWN":"說的沒錯！把動物放在不合適的環境中，只會增加牠們的壓力！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"이러한 교훈은 브레멘 동물전대 에피소드에서도 확인할 수 있다.","JPN":"このような教訓は、ブレーメンの動物戦隊のエピソードからも確認できる。","ENG":"There's an episode of Town Soldiers of Bremen about that.","TWN":"這一點布萊梅動物戰隊裡也有說！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"팬더인 탐탐 상사도 전쟁터에서 구조한 아기펭귄이 대나무에 적응하지 못한 탓에, 결국 새로운 가족을 찾아줘야만 했지.","JPN":"パンダのタムタム軍曹も、戦場から救助した赤ちゃんペンギンが\\n竹に適応できなかったため、結局新しい家族を探さなければならなかったのだ。","ENG":"Master Sergeant Tam-tam, the panda, rescued a baby penguin from the battlefield, but he couldn't get used to the bamboo forest. He had to be sent away.","TWN":"裡面有一集是說，熊貓在戰場上救援的小企鵝，因為無法適應竹林生活，最後只好另外幫牠找新的家人！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아, 나도 그 편 봤어!","JPN":"あ、そのエピソードは私も見たよ！","ENG":"Oh, I watched that episode, too!","TWN":"喔～那一集我也有看！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그때 입양된 펭귄이 성장해서 우주 대악당 안드레아스 소령이 되는 거잖아?","JPN":"あの時里子に出されたペンギンが成長して、\\n宇宙の大悪党アンドレア少佐になるんだよね？","ENG":"That penguin grows into the great space villain, Major Andreas, right?","TWN":"後來那隻企鵝不是黑化成宇宙無敵大壞蛋嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그렇다. 시리즈에서도 손꼽히는 비극이지.","JPN":"そう。シリーズの中でも1、2位を争う悲劇である。","ENG":"That's right. It's one of the biggest tragedies in the series.","TWN":"沒錯，這真是人間悲劇！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그러니 우리도 막시무스의 새로운 가족이 될 사람을 신중하게 찾을 필요가 있다.","JPN":"だから本官たちもマクシムスの新しい家族になる人は、慎重に探す必要がある。","ENG":"That means we must be careful to find Maximus's new family.","TWN":"所以我們也要慎重地幫咖啡貓找家才行！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그치? 우리 귀여운 안토니오는 착한 주인을 만나서 스미스 병장처럼 정의롭게 자랐으면 좋겠네!","JPN":"そうね！　こんなに可愛いアントニオなんだから、\\n優しい里親さんのところでスミス兵長のように正義感あふれる子に育ってほしいね！","ENG":"I agree. I hope our cute Antonio meets a good owner and grows up to be as righteous as Sergeant Smith.","TWN":"沒錯！我們湯姆喵這麼可愛！一定要幫牠找個好人家，長大後才不會走鐘！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"두 분…… 고양이를 부르는 이름은 하나로 통일하는 게 좋지 않을까요?","JPN":"あの、2人とも……とりあえず猫ちゃんの名前は1つに統一しませんか？","ENG":"You two... Why don't you use the same name for the cat?","TWN":"那個……一隻貓是不是取一個名字就好？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그리고 저도 고양이에게 좋은 주인을 찾아주는 건 찬성이에요.","JPN":"そして私も、この子に新しい里親を探してあげるのは賛成。","ENG":"Also, I agree that we find a good owner for him.","TWN":"另外，我也讚成替貓咪找好人家！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"근데 누구한테 맡기죠?","JPN":"でも、誰にお願いすればいいかな？","ENG":"But who should that be?","TWN":"那有合適的鏟屎官嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"애석하게도 본관에게는 막시무스 이병을 맡길 좋은 사람이 떠오르지 않는다.","JPN":"残念なことに、本官にはマクシムス二等兵を預けられるような人が思い浮かばない。","ENG":"Unfortunately, I can't think of anyone whom I can trust with Private Maximus.","TWN":"可惜，我目前腦袋裡沒有適合託付咖啡貓的人選。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"나도 친구들에게 말은 해보겠지만…… 다들 학생이라, 너무 기대하진 않는 편이 좋을 것 같아.","JPN":"私も友達に聞いてみるけど……\\nみんな学生だし、あまり期待しない方がいいかも。","ENG":"I can talk to my friends, but all of them are students. I doubt any one of them can take him in.","TWN":"我也會問問我朋友……但大家都是大學生，還是不要抱有期待比較好。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"으음…","JPN":"う～ん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"역시 그 방법 밖에 없겠어요!","JPN":"やっぱりあの方法しかありませんね！","ENG":"I've got an idea.","TWN":"果然只剩那個方法！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"오오, 벌써 방법을 생각해내다니. 역시 대장이다!","JPN":"おお、もう解決策を思いつくとは、さすが隊長だ！","ENG":"Oooh, you came up with an idea already. That's why you're the captain!","TWN":"喔！你這麼快就想到方法啦？真不愧是老大！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그 방법이라는 게 어떤 거야, 하림아?","JPN":"その方法って？　詳しく教えて、ウサギちゃん！","ENG":"What is it, Harim?","TWN":"是什麼方法呢？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"와아! 과자! 이번에도 엄청나게 많아!","JPN":"わぁ！　お菓子だ！　今回もすごい量だ！","ENG":"Whoa, cookies! So many cookies, just like the last time!","TWN":"哇！這次也有好多餅乾！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지난 번에 여러분이 학생회실을 찾아준 덕분입니다.","JPN":"この前皆さんが生徒会室にお越しくださったお陰です。","ENG":"I'd like to thank you for visiting the Student Council office the last time.","TWN":"多虧你們上次造訪學生會，"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그 이후로 더는 학생회를 어렵게 생각하지 않고 직접 찾아와 의견을 나누는 학생들이 많아졌어요.","JPN":"あれから生徒会のことを身近な存在と思ってくれたのか、\\n直接やって来て意見を交換する生徒が増えました。","ENG":"You've inspired many other students to pluck up the courage to come to the Council and share their opinions with it.","TWN":"在那之後，學生們不再覺得學生會難以親近，也開始有許多學生開始會直接到學生會表達意見。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래서 최근 방문자들을 위해 제과업체와 추가적인 공급 계약을 맺게 됐죠.","JPN":"それで先日、訪問者のために製菓業者と供給契約を結ぶことになりました。","ENG":"So, we've hired additional bakeries to get more snacks for the visitors.","TWN":"所以我們特別和餅乾業者簽約，用這些餅乾來招待造訪的學生。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"과자는 얼마든지 있으니 마음껏 들어도 좋아요.","JPN":"お菓子はたくさんあるので、どうぞ召し上がってください。","ENG":"We've got plenty of cookies. Have your fill.","TWN":"餅乾要多少有多少，你們千萬不要客氣！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"감사합니다, 통큰 사부님!","JPN":"ありがとうございます、太っ腹な師匠！","ENG":"Thank you. You're so generous, Master!","TWN":"謝謝你～"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래서, 저에게 따로 볼 일이 있어서 왔다고요?","JPN":"それで、私にご用件があるとお聞きしましたが。","ENG":"So, what is this thing that you'd like to talk to me about?","TWN":"不過，你們來找我是有別的事嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 네.","JPN":"あっ、はい。","ENG":"Oh, right.","TWN":"喔！對喔！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"오늘은 도움을 부탁드리기보다 회장님의 의견을 여쭤보려고 왔어요.","JPN":"今日は用件っていうか、会長の意見が聞きたくて来たんです。","ENG":"We didn't come to ask you for your help today. We came to ask your opinion on something.","TWN":"我們今天來找你，是有件事想問問你的意見。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"말씀하세요. 어떤 질문이든 답변해드리겠습니다.","JPN":"はい、どうぞ。どんな質問でもお答えしますよ。","ENG":"Tell me. I'll answer you as best as I can.","TWN":"請說，我會盡我所能地回答。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"사부, 동물 좋아하시죠? 지난 번에 알렉산더를 안아 보셨을 때도 좋아하셨고요!","JPN":"師匠は動物は好きですよね？\\nこの前アレクサンダーを抱っこした時も喜んでいましたよね！？","ENG":"Master, you like animals, right? You loved holding Alexander the last time.","TWN":"你喜歡動物吧？上次看你抱亞歷山大的時候好像很開心。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"음…… 확실히 그때의 감촉은 잊을 수 없군요.","JPN":"確かに……あの時の感触は忘れられませんね。","ENG":"Mm... I still can't forget how soft he felt.","TWN":"嗯……那時候的觸感確實令人難忘。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여러분의 말처럼 저는……","JPN":"皆さんのおっしゃるとおり、私は……","ENG":"You're right. I...","TWN":"可能真的就像你們說的……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"동물을 좋아하고 있을 지도 모르겠네요.","JPN":"動物が好きかもしれませんね。","ENG":"Maybe I do like animals.","TWN":"我好像喜歡動物！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"혹시 그 강아지 알렉산더에게 다시 무슨 일이 생긴 건가요?","JPN":"あの仔犬のアレクサンダーにまた何かあったのですか？","ENG":"Did something else happen to that dog, Alexander?","TWN":"難道是那隻叫亞歷山大的狗狗又發生什麼事嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아뇨, 사실은 말이죠…","JPN":"いえ、実はですね……","ENG":"No. Actually...","TWN":"不是的，事情是這樣的…"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"냐앙!","JPN":"ニャーン！","ENG":"Meow!","TWN":"喵喵！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 막시무스 이병! 쿠키는 먹으면 안 된다!","JPN":"おっと、マクシムス二等兵！　クッキーはダメだぞ！","ENG":"Ah, Private Maximus! You can't eat the cookies!","TWN":"欸！咖啡貓二等兵，你不能吃餅乾啦！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이건… 고양이?","JPN":"これは……猫？","ENG":"This is... a cat.","TWN":"這是…貓？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"강아지 못지 않게 부드러운 털을 가지고 있군요.","JPN":"犬のように柔らかい毛並みですね。","ENG":"Its hair looks as soft as the dog's.","TWN":"毛的觸感不會比狗差呢！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"실례가 안 된다면 만져봐도 괜찮을까요, 막시무스?","JPN":"失礼でなければ撫でてみてもいいですか、マクシムス？","ENG":"Mind if I touch you, Maximus?","TWN":"請問我可以摸摸你嗎？咖啡貓？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네- 고양이는 쿠키를 먹으면 안 된답니다.","JPN":"あ、猫にクッキーはいけませんよ。","ENG":"And no, cats shouldn't eat cookies.","TWN":"是的，貓是不能吃餅乾的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 이 무염 육포라면 괜찮을지도 모르겠네요.","JPN":"でも、この無塩ジャーキーなら大丈夫かもしれません。","ENG":"But maybe he can eat this unsalted beef jerky.","TWN":"但無添加的肉泥應該是可以的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"앗, 회장님이 벌써 안토니오와 소통하기 시작했어!","JPN":"おお、会長がもうアントニオとコミュニケーションを取り始めたよ！","ENG":"Ah, the President is already building rapport with Antonio!","TWN":"哇～會長已經開始和湯姆喵對話咧！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"막시무스의 마음을 꿰뚫어보는 사람이라니! 틀림없이 좋은 주인이 될 것 같군.","JPN":"マクシムスの心を見抜くとは！　きっと良い飼い主になりそうだな。","ENG":"She knows what Maximus wants. She'll be a good owner for him.","TWN":"竟然可以聽見咖啡貓的心聲！你果然就是最合適的鏟屎官！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"고양이 간식업체…… 추가 계약할까","JPN":"猫のおやつ業者と……追加契約しようかしら。","ENG":"Maybe we should hire a cat treat company, too...","TWN":"需要……另外和貓零食業者簽約嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"회장님이 어느새 고양이 털에 얼굴을 파묻고 있어.","JPN":"会長がいつの間にか猫のお腹に顔を埋めている。","ENG":"The President now has her face buried in the cat's hair.","TWN":"會長吸起貓來咧！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"사부, 흠뻑 빠진 것 같은데?","JPN":"師匠、すでにメロメロになってる……？","ENG":"The Master's in love.","TWN":"會長，是不是有點太沉迷？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"오기 전에 막시무스 이병의 털을 정리해두길 잘한 것 같군. 이건 좋은 징조로 보인다.","JPN":"ここに来る前にマクシムス二等兵にブラッシングしておいて正解だったな。\\nいい感じだぞ。","ENG":"It was good that I groomed Private Maximus's hair before we came. This is a good sign.","TWN":"幸好我們來之前有先幫咖啡貓二等兵把毛理好，真是聰明。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……음?","JPN":"……ん？","ENG":"... Mm?","TWN":"……嗯？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이런, 실례했어요.","JPN":"ああ、失礼。","ENG":"Oh, my apologies.","TWN":"抱歉，我失態了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회장으로서 이런 평정심을 잃은 모습을 보이다니. 저도 아직 많이 부족하군요.","JPN":"生徒会長として平常心が乱れた姿をお見せしてしまいました。\\n私もまだまだですね。","ENG":"I can't believe I've lost my composure so quickly. As the Student President, I'm ashamed.","TWN":"身為學生會長，竟然被人看到如此失態的樣子，看來我的操練還不夠。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래서, 란체스터 2세를 어떤 이유로 여기까지 데려오게 된 건가요?","JPN":"それで、どのような理由でランチェスター2世をこちらまで連れてきたのですか？","ENG":"So, what brings Lanchester II all the way here, if you don't mind my asking?","TWN":"不過，你們怎麼會把蘭賈斯特二世帶來這裡呢？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"어… 그게 그러니까…","JPN":"えっと……それが……","ENG":"Err, that's... Mm...","TWN":"這個嘛…因為…"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"우린 지금 떠돌이가 된 막시무스 이병이 마음 놓고 지낼 수 있는 곳을 찾고 있다.","JPN":"本官たちは身寄りのないマクシムス二等兵が、心置きなく過ごせる場所を探している。","ENG":"Right now, Private Maximus has no place to stay. We're looking for a good home for him.","TWN":"我們正在幫浪浪咖啡貓二等兵尋找可以安心落腳的地方！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"맞아요! 그래서 제가 사부의 덕목이라면 분명 고양이를 잘 돌봐줄 수 있을 거라고 강력추천했거든요!","JPN":"そうなんです！\\n師匠ならきっと猫ちゃんのお世話を安心して任せられると思いまして！","ENG":"Yes, and since you're such a great person, I thought you could take good care of him, too.","TWN":"對啊！我立刻就推薦你！你人美心也美，一定會好好照顧湯姆喵！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그런 일이 있었군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來是這樣。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 저는 학생 여러분의 건강하고 올곧은 아카데미 생활을 위해 짊어져야할 책임이 있습니다.","JPN":"しかし私は、生徒の皆さんが安全かつ円滑にアカデミー生活を送るために責任を果たさなければならない立場です。","ENG":"But I have responsibilities to my students. Their healthy, productive academic life depends on me.","TWN":"不過我身為學生會長，有責任維護學院的環境，以學生的健康為第一考量。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"란체스터 2세는 분명 매력적인 고양이지만, 지금의 저로서는 성심을 다하기 어려울 것 같군요.","JPN":"ランチェスター2世は確かに魅力的な猫ではありますが、\\n今の私では誠心誠意尽くすことが難しいでしょう。","ENG":"Lanchester II is definitely an attractive cat, but I don't think I can give him the care he needs.","TWN":"我承認蘭賈斯特二世是隻非常有魅力的貓，但現在的我沒有餘力可以成為牠的主人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아쉽네요.","JPN":"残念です……","ENG":"This is unfortunate.","TWN":"好可惜喔～"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제가 란체스터 2세를 위해 해줄 수 있는 건 기껏해야 1일 3간식과 털손질, 놀아주기, 자장가 불러주기 정도일 것 같습니다만…","JPN":"私がランチェスター2世のためにできることは、\\nせいぜい1日3回のおやつと毛の手入れ、お遊び、子守唄を歌う程度だと思います。","ENG":"The only things I could do for Lanchester II would be feeding him treats three times a day, grooming his hair, playing with him, singing him a lullaby...","TWN":"我能夠為蘭賈斯特二世做的，就只有1天餵3次零食、美容、陪牠玩、唱晚安曲給牠聽而已…"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"어떻게 하지, 대장? 아무래도 보스는 막시무스가 부담이 되는 입장인 것 같다.","JPN":"どうする、隊長？\\nどうやらボスは立場的にマクシムスが負担になるようだ。","ENG":"What do we do, Captain? I don't think the Boss feels comfortable taking Maximus in.","TWN":"老大，這該怎麼辦才好？養咖啡貓對會長來說好像很有壓力。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으응… 어쩔 수 없지. 확실히 회장에겐 회장으로서의 책무라는 게 있으니까.","JPN":"うーん…仕方ないね。確かに、会長には会長としての責務があるから。","ENG":"Mm... It's understandable. The President does have responsibilities as president.","TWN":"嗯嗯…沒辦法，會長要考量的確實比較多。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…음, 이디스에게 부탁해서 쥐 장난감을 만들어보는 것 정도는 할 수 있겠네요. 분명 그 말랑말랑한 발바닥을 휘적이면서 재미있게 놀 수 있겠죠.","JPN":"そうですね……イーディスに頼んでネズミのオモチャを作ることくらいはできますね。きっと、このぷにぷにの肉球を振り回しながら遊べるでしょう。","ENG":"Mm, maybe I could ask Edith to make a rat toy for him, too. He'd love to go after it, swiping his soft pink pads at it.","TWN":"嗯…拜託伊蒂絲做個老鼠玩具的話，這點我還辦得到。看那軟綿綿的肉球揮來揮去一定很可愛！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"신경 써주셔서 감사해요, 회장님. 무리시면 고양이의 보호자는 좀 더 찾아볼게요. 시간 내주셔서 고맙습니다.","JPN":"それだけでも嬉しいです、会長。飼い主になってくれそうな方を他にも探してみます。お時間ありがとうございました！","ENG":"Thank you for talking to us, President. We'll find someone else to take care of the cat. Thank you for your time, too.","TWN":"謝謝你的用心，我們會另外找合適的人選，謝謝你抽空見我們。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"사부, 고맙습니다~ 또 놀러올게요!","JPN":"師匠、ありがとうございます！　また遊びに来ます！","ENG":"Master, thanks. We'll come again!","TWN":"謝謝你～我們會再來玩的！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L32_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"호의에 감사한다. 과자도 감사한다. 그럼 우리에겐 다음 임무가 있으니 실례하지.","JPN":"好意に感謝する。お菓子も美味しかった。では、本官たちは次の任務があるので、この辺で失礼する。","ENG":"Thank you for your kindness. And cookies. Now, if you'll excuse us, we've got a mission to accomplish.","TWN":"謝謝你的好意和餅乾。我們還有任務在身，告辭！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_WOOD"},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이런 부족한 나라도 괜찮다면 란체스터 2세. 제가 당신의 삶을 책임지고 행복하게……","JPN":"こんな私でもよければランチェスター2世、私があなたの人生に責任を持って幸せに……","ENG":"Lanchester II, I may not be a perfect owner for you, but still, if you accept me, I promise I'll take good care of—","TWN":"蘭賈斯特二世，你不嫌棄的話，就讓我來照顧你的下半輩子……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm?","TWN":"嗯…？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};